SELECT 
FROM supplier_wallet_settlements

    AND status != 'deleted'
    AND id = #{id, jdbcType=BIGINT}
    AND supplier_id = #{supplierId, jdbcType=BIGINT}
    AND settlement_month = #{settlementMonth, jdbcType=VARCHAR}
    AND total_income = #{totalIncome, jdbcType=DECIMAL}
    AND withdrawable_amount = #{withdrawableAmount, jdbcType=DECIMAL}
    AND frozen_amount = #{frozenAmount, jdbcType=DECIMAL}
    AND order_amount = #{orderAmount, jdbcType=DECIMAL}
    AND delivery_fee = #{deliveryFee, jdbcType=DECIMAL}
    AND installation_fee = #{installationFee, jdbcType=DECIMAL}
    AND refund_deduction = #{refundDeduction, jdbcType=DECIMAL}
    AND aftersale_deduction = #{aftersaleDeduction, jdbcType=DECIMAL}
